     1→import React, { useState, useEffect } from 'react';
     2→import type { Task } from '../types';
     3→
     4→interface RecurrencePickerProps {
     5→  value: Task['recurrence'];
     6→  onChange: (recurrence: Task['recurrence']) => void;
     7→  onClose?: () => void;
     8→}
     9→
    10→/**
    11→ * RecurrencePicker Component
    12→ * UI for setting up recurring task patterns
    13→ *
    14→ * Features:
    15→ * - Frequency selection (daily, weekly, monthly, yearly)
    16→ * - Interval input (every X days/weeks/months/years)
    17→ * - Day of week picker (for weekly)
    18→ * - Day of month picker (for monthly)
    19→ * - End condition (never, after X occurrences, until date)
    20→ * - Clear visual feedback
    21→ * - Matches Calendar event recurrence UI patterns
    22→ */
    23→export const RecurrencePicker: React.FC<RecurrencePickerProps> = ({
    24→  value,
    25→  onChange,
    26→  onClose,
    27→}) => {
    28→  // Local state (synced with value prop)
    29→  const [frequency, setFrequency] = useState<'daily' | 'weekly' | 'monthly' | 'yearly'>(
    30→    value?.frequency || 'weekly'
    31→  );
    32→  const [interval, setInterval] = useState<number>(value?.interval || 1);
    33→  const [daysOfWeek, setDaysOfWeek] = useState<number[]>(value?.daysOfWeek || []);
    34→  const [dayOfMonth, setDayOfMonth] = useState<number | undefined>(value?.dayOfMonth);
    35→  const [endType, setEndType] = useState<'never' | 'after' | 'until'>(value?.endType || 'never');
    36→  const [endCount, setEndCount] = useState<number | undefined>(value?.endCount);
    37→  const [endDate, setEndDate] = useState<string | undefined>(value?.endDate);
    38→  const [recurFromCompletion, setRecurFromCompletion] = useState<boolean>(value?.recurFromCompletion || false);
    39→
    40→  // Sync local state with value prop when it changes
    41→  useEffect(() => {
    42→    if (value) {
    43→      setFrequency(value.frequency);
    44→      setInterval(value.interval);
    45→      setDaysOfWeek(value.daysOfWeek || []);
    46→      setDayOfMonth(value.dayOfMonth);
    47→      setEndType(value.endType);
    48→      setEndCount(value.endCount);
    49→      setEndDate(value.endDate);
    50→      setRecurFromCompletion(value.recurFromCompletion || false);
    51→    }
    52→  }, [value]);
    53→
    54→  // Helper: Toggle day of week selection
    55→  const toggleDayOfWeek = (day: number) => {
    56→    setDaysOfWeek((prev) =>
    57→      prev.includes(day) ? prev.filter((d) => d !== day) : [...prev, day].sort((a, b) => a - b)
    58→    );
    59→  };
    60→
    61→  // Helper: Build recurrence summary text
    62→  const getRecurrenceSummary = (): string => {
    63→    let summary = 'Repeats ';
    64→
    65→    // Frequency and interval
    66→    if (interval === 1) {
    67→      summary += frequency;
    68→    } else {
    69→      summary += `every ${interval} ${frequency === 'daily' ? 'days' : frequency === 'weekly' ? 'weeks' : frequency === 'monthly' ? 'months' : 'years'}`;
    70→    }
    71→
    72→    // Days of week (for weekly)
    73→    if (frequency === 'weekly' && daysOfWeek.length > 0) {
    74→      const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
    75→      const selectedDays = daysOfWeek.map((d) => dayNames[d]).join(', ');
    76→      summary += ` on ${selectedDays}`;
    77→    }
    78→
    79→    // Day of month (for monthly)
    80→    if (frequency === 'monthly' && dayOfMonth) {
    81→      summary += ` on day ${dayOfMonth}`;
    82→    }
    83→
    84→    // End condition
    85→    if (endType === 'after' && endCount) {
    86→      summary += `, ends after ${endCount} occurrences`;
    87→    } else if (endType === 'until' && endDate) {
    88→      summary += `, ends on ${endDate}`;
    89→    }
    90→
    91→    return summary;
    92→  };
    93→
    94→  // Save recurrence and call onChange
    95→  const handleSave = () => {
    96→    const recurrence: Task['recurrence'] = {
    97→      frequency,
    98→      interval,
    99→      daysOfWeek: frequency === 'weekly' ? daysOfWeek : undefined,
   100→      dayOfMonth: frequency === 'monthly' ? dayOfMonth : undefined,
   101→      endType,
   102→      endCount: endType === 'after' ? endCount : undefined,
   103→      endDate: endType === 'until' ? endDate : undefined,
   104→      recurFromCompletion,
   105→    };
   106→
   107→    onChange(recurrence);
   108→    if (onClose) onClose();
   109→  };
   110→
   111→  // Clear recurrence
   112→  const handleClear = () => {
   113→    onChange(undefined);
   114→    if (onClose) onClose();
   115→  };
   116→
   117→  return (
   118→    <div className="space-y-4 p-4 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg">
   119→      {/* Header */}
   120→      <div className="flex items-center justify-between">
   121→        <h3 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary">
   122→          Set Recurrence
   123→        </h3>
   124→        {value && (
   125→          <button
   126→            onClick={handleClear}
   127→            className="text-xs text-red-500 hover:text-red-600 dark:text-red-400 dark:hover:text-red-300"
   128→          >
   129→            Clear
   130→          </button>
   131→        )}
   132→      </div>
   133→
   134→      {/* Frequency */}
   135→      <div>
   136→        <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
   137→          Frequency
   138→        </label>
   139→        <select
   140→          value={frequency}
   141→          onChange={(e) => setFrequency(e.target.value as 'daily' | 'weekly' | 'monthly' | 'yearly')}
   142→          className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
   143→        >
   144→          <option value="daily">Daily</option>
   145→          <option value="weekly">Weekly</option>
   146→          <option value="monthly">Monthly</option>
   147→          <option value="yearly">Yearly</option>
   148→        </select>
   149→      </div>
   150→
   151→      {/* Interval */}
   152→      <div>
   153→        <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
   154→          Repeat every
   155→        </label>
   156→        <div className="flex items-center gap-2">
   157→          <input
   158→            type="number"
   159→            min="1"
   160→            max="999"
   161→            value={interval}
   162→            onChange={(e) => setInterval(Math.max(1, parseInt(e.target.value) || 1))}
   163→            className="w-20 p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
   164→          />
   165→          <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
   166→            {frequency === 'daily' && (interval === 1 ? 'day' : 'days')}
   167→            {frequency === 'weekly' && (interval === 1 ? 'week' : 'weeks')}
   168→            {frequency === 'monthly' && (interval === 1 ? 'month' : 'months')}
   169→            {frequency === 'yearly' && (interval === 1 ? 'year' : 'years')}
   170→          </span>
   171→        </div>
   172→      </div>
   173→
   174→      {/* Days of Week (for weekly) */}
   175→      {frequency === 'weekly' && (
   176→        <div>
   177→          <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
   178→            Repeat on
   179→          </label>
   180→          <div className="flex gap-2">
   181→            {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map((day, index) => (
   182→              <button
   183→                key={day}
   184→                onClick={() => toggleDayOfWeek(index)}
   185→                className={`
   186→                  flex-1 py-2 px-1 text-xs font-medium rounded-lg transition-colors
   187→                  ${
   188→                    daysOfWeek.includes(index)
   189→                      ? 'bg-accent-blue text-white'
   190→                      : 'bg-surface-light-elevated dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-neutral-700'
   191→                  }
   192→                `}
   193→              >
   194→                {day}
   195→              </button>
   196→            ))}
   197→          </div>
   198→        </div>
   199→      )}
   200→
   201→      {/* Day of Month (for monthly) */}
   202→      {frequency === 'monthly' && (
   203→        <div>
   204→          <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
   205→            Day of month
   206→          </label>
   207→          <input
   208→            type="number"
   209→            min="1"
   210→            max="31"
   211→            value={dayOfMonth || ''}
   212→            onChange={(e) => {
   213→              const val = parseInt(e.target.value);
   214→              setDayOfMonth(val >= 1 && val <= 31 ? val : undefined);
   215→            }}
   216→            placeholder="1-31"
   217→            className="w-24 p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
   218→          />
   219→          <p className="mt-1 text-xs text-text-light-secondary dark:text-text-dark-secondary">
   220→            Leave empty to use the current day of month
   221→          </p>
   222→        </div>
   223→      )}
   224→
   225→      {/* Recur from Completion Date */}
   226→      <div>
   227→        <label className="flex items-center gap-2 cursor-pointer">
   228→          <input
   229→            type="checkbox"
   230→            checked={recurFromCompletion}
   231→            onChange={(e) => setRecurFromCompletion(e.target.checked)}
   232→            className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue rounded"
   233→          />
   234→          <span className="text-sm text-text-light-primary dark:text-text-dark-primary">
   235→            Recur from completion date
   236→          </span>
   237→        </label>
   238→        <p className="mt-1 ml-6 text-xs text-text-light-secondary dark:text-text-dark-secondary">
   239→          When enabled, next occurrence is calculated from when you complete the task (not from the due date)
   240→        </p>
   241→      </div>
   242→
   243→      {/* End Condition */}
   244→      <div>
   245→        <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
   246→          Ends
   247→        </label>
   248→        <div className="space-y-3">
   249→          {/* Never */}
   250→          <label className="flex items-center gap-2 cursor-pointer">
   251→            <input
   252→              type="radio"
   253→              name="endType"
   254→              checked={endType === 'never'}
   255→              onChange={() => setEndType('never')}
   256→              className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue"
   257→            />
   258→            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">Never</span>
   259→          </label>
   260→
   261→          {/* After X occurrences */}
   262→          <label className="flex items-center gap-2 cursor-pointer">
   263→            <input
   264→              type="radio"
   265→              name="endType"
   266→              checked={endType === 'after'}
   267→              onChange={() => setEndType('after')}
   268→              className="w-4 h-4 text-accent-blue focus:ring-2 focus:ring-accent-blue"
   269→            />
   270→            <span className="text-sm text-text-light-primary dark:text-text-dark-primary">After</span>
   271→            <input
   272→              type="number"
   273→              min="1"
   274→              max="999"
   275→              value={endCount || ''}
