/**
 * Natural Language Recurrence Parser
 * Converts human-readable phrases into RecurrenceRule objects
 *
 * Supported phrases:
 * - Daily: "every day", "every 3 days", "daily", "every weekday"
 * - Weekly: "every week", "every Monday", "every 2 weeks on Friday", "weekly"
 * - Monthly: "every month", "every 15th", "every last Friday", "monthly on the 10th"
 * - Yearly: "every year", "annually", "every January 15th"
 */

import type { Task } from '../types';

type RecurrenceRule = NonNullable<Task['recurrence']>;

/**
 * Parse a natural language string into a RecurrenceRule
 * @param input Human-readable recurrence description
 * @returns RecurrenceRule object or null if unparseable
 */
export function parseRecurrenceNaturalLanguage(input: string): RecurrenceRule | null {
  if (!input || typeof input !== 'string') {
    return null;
  }

  // Normalize: lowercase, trim, collapse whitespace
  const normalized = input.toLowerCase().trim().replace(/\s+/g, ' ');

  // Try parsing each frequency type
  return (
    parseDailyPattern(normalized) ||
    parseWeeklyPattern(normalized) ||
    parseMonthlyPattern(normalized) ||
    parseYearlyPattern(normalized)
  );
}

/**
 * Parse daily recurrence patterns
 * Examples: "every day", "every 3 days", "daily", "every weekday"
 */
function parseDailyPattern(input: string): RecurrenceRule | null {
  // Pattern 1: "every day" or "daily"
  if (/^(every\s+day|daily)$/.test(input)) {
    return {
      frequency: 'daily',
      interval: 1,
      endType: 'never',
    };
  }

  // Pattern 2: "every X days"
  const everyXDays = /^every\s+(\d+)\s+days?$/.exec(input);
  if (everyXDays) {
    const interval = parseInt(everyXDays[1], 10);
    if (interval > 0 && interval <= 999) {
      return {
        frequency: 'daily',
        interval,
        endType: 'never',
      };
    }
  }

  // Pattern 3: "every weekday" (Mon-Fri)
  if (/^every\s+weekdays?$/.test(input)) {
    return {
      frequency: 'weekly',
      interval: 1,
      daysOfWeek: [1, 2, 3, 4, 5], // Mon-Fri
      endType: 'never',
    };
  }

  return null;
}

/**
 * Parse weekly recurrence patterns
 * Examples: "every week", "every Monday", "every 2 weeks on Friday", "weekly"
 */
function parseWeeklyPattern(input: string): RecurrenceRule | null {
  const dayNames = ['sunday', 'monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday'];
  const dayAbbreviations = ['sun', 'mon', 'tue', 'wed', 'thu', 'fri', 'sat'];

  // Pattern 1: "every week" or "weekly"
  if (/^(every\s+week|weekly)$/.test(input)) {
    return {
      frequency: 'weekly',
      interval: 1,
      endType: 'never',
    };
  }

  // Pattern 2: "every Monday" (single day)
  const everySingleDay = /^every\s+(\w+)$/.exec(input);
  if (everySingleDay) {
    const dayName = everySingleDay[1];
    const dayIndex = dayNames.indexOf(dayName);
    const dayAbbrevIndex = dayAbbreviations.indexOf(dayName);

    if (dayIndex !== -1) {
      return {
        frequency: 'weekly',
        interval: 1,
        daysOfWeek: [dayIndex],
        endType: 'never',
      };
    }
    if (dayAbbrevIndex !== -1) {
      return {
        frequency: 'weekly',
        interval: 1,
        daysOfWeek: [dayAbbrevIndex],
        endType: 'never',
      };
    }
  }

  // Pattern 3: "every 2 weeks on Friday"
  const everyXWeeksOnDay = /^every\s+(\d+)\s+weeks?\s+on\s+(\w+)$/.exec(input);
  if (everyXWeeksOnDay) {
    const interval = parseInt(everyXWeeksOnDay[1], 10);
    const dayName = everyXWeeksOnDay[2];
    const dayIndex = dayNames.indexOf(dayName);
    const dayAbbrevIndex = dayAbbreviations.indexOf(dayName);

    if (interval > 0 && interval <= 999 && (dayIndex !== -1 || dayAbbrevIndex !== -1)) {
      return {
        frequency: 'weekly',
        interval,
        daysOfWeek: [dayIndex !== -1 ? dayIndex : dayAbbrevIndex],
        endType: 'never',
      };
    }
  }

  // Pattern 4: "every X weeks"
  const everyXWeeks = /^every\s+(\d+)\s+weeks?$/.exec(input);
  if (everyXWeeks) {
    const interval = parseInt(everyXWeeks[1], 10);
    if (interval > 0 && interval <= 999) {
      return {
        frequency: 'weekly',
        interval,
        endType: 'never',
      };
    }
  }

  return null;
}

/**
 * Parse monthly recurrence patterns
 * Examples: "every month", "every 15th", "every last Friday", "monthly on the 10th"
 */
function parseMonthlyPattern(input: string): RecurrenceRule | null {
  // Pattern 1: "every month" or "monthly"
  if (/^(every\s+month|monthly)$/.test(input)) {
    return {
      frequency: 'monthly',
      interval: 1,
      endType: 'never',
    };
  }

  // Pattern 2: "every 15th" or "every 1st" (day of month)
  const everyDayOfMonth = /^every\s+(\d{1,2})(?:st|nd|rd|th)?$/.exec(input);
  if (everyDayOfMonth) {
    const dayOfMonth = parseInt(everyDayOfMonth[1], 10);
    if (dayOfMonth >= 1 && dayOfMonth <= 31) {
      return {
        frequency: 'monthly',
        interval: 1,
        dayOfMonth,
        endType: 'never',
      };
    }
  }

  // Pattern 3: "monthly on the 10th"
  const monthlyOnThe = /^monthly\s+on\s+the\s+(\d{1,2})(?:st|nd|rd|th)?$/.exec(input);
  if (monthlyOnThe) {
    const dayOfMonth = parseInt(monthlyOnThe[1], 10);
    if (dayOfMonth >= 1 && dayOfMonth <= 31) {
      return {
        frequency: 'monthly',
        interval: 1,
        dayOfMonth,
        endType: 'never',
      };
    }
  }

  // Pattern 4: "every X months"
  const everyXMonths = /^every\s+(\d+)\s+months?$/.exec(input);
  if (everyXMonths) {
    const interval = parseInt(everyXMonths[1], 10);
    if (interval > 0 && interval <= 999) {
      return {
        frequency: 'monthly',
        interval,
        endType: 'never',
      };
    }
  }

  // Pattern 5: "every X months on the 15th"
  const everyXMonthsOnDay = /^every\s+(\d+)\s+months?\s+on\s+the\s+(\d{1,2})(?:st|nd|rd|th)?$/.exec(input);
  if (everyXMonthsOnDay) {
    const interval = parseInt(everyXMonthsOnDay[1], 10);
    const dayOfMonth = parseInt(everyXMonthsOnDay[2], 10);
    if (interval > 0 && interval <= 999 && dayOfMonth >= 1 && dayOfMonth <= 31) {
      return {
        frequency: 'monthly',
        interval,
        dayOfMonth,
        endType: 'never',
      };
    }
  }

  // Note: "every last Friday" requires more complex parsing (nth weekday of month)
  // This is not supported in the current RecurrenceRule schema

  return null;
}

/**
 * Parse yearly recurrence patterns
 * Examples: "every year", "annually", "every January 15th"
 */
function parseYearlyPattern(input: string): RecurrenceRule | null {
  const monthNames = [
    'january', 'february', 'march', 'april', 'may', 'june',
    'july', 'august', 'september', 'october', 'november', 'december'
  ];
  const monthAbbreviations = ['jan', 'feb', 'mar', 'apr', 'may', 'jun', 'jul', 'aug', 'sep', 'oct', 'nov', 'dec'];

  // Pattern 1: "every year" or "annually"
  if (/^(every\s+year|annually)$/.test(input)) {
    return {
      frequency: 'yearly',
      interval: 1,
      endType: 'never',
    };
  }

  // Pattern 2: "every X years"
  const everyXYears = /^every\s+(\d+)\s+years?$/.exec(input);
  if (everyXYears) {
    const interval = parseInt(everyXYears[1], 10);
    if (interval > 0 && interval <= 999) {
      return {
        frequency: 'yearly',
        interval,
        endType: 'never',
      };
    }
  }

  // Pattern 3: "every January 15th" (month + day)
  // Note: Current RecurrenceRule schema doesn't support month specification for yearly
  // This would require extending the schema with monthOfYear field
  const everyMonthDay = /^every\s+(\w+)\s+(\d{1,2})(?:st|nd|rd|th)?$/.exec(input);
  if (everyMonthDay) {
    const monthName = everyMonthDay[1];
    const monthIndex = monthNames.indexOf(monthName);
    const monthAbbrevIndex = monthAbbreviations.indexOf(monthName);

    if (monthIndex !== -1 || monthAbbrevIndex !== -1) {
      const dayOfMonth = parseInt(everyMonthDay[2], 10);
      if (dayOfMonth >= 1 && dayOfMonth <= 31) {
        // For now, return yearly without month specification
        // Future: extend RecurrenceRule to support monthOfYear
        return {
          frequency: 'yearly',
          interval: 1,
          endType: 'never',
        };
      }
    }
  }

  return null;
}

/**
 * Generate a human-readable summary from a RecurrenceRule
 * @param rule RecurrenceRule object
 * @returns Human-readable description
 */
export function formatRecurrenceRule(rule: RecurrenceRule): string {
  let summary = 'Repeats ';

  // Frequency and interval
  if (rule.interval === 1) {
    summary += rule.frequency;
  } else {
    const unit = {
      daily: 'days',
      weekly: 'weeks',
      monthly: 'months',
      yearly: 'years',
    }[rule.frequency];
    summary += `every ${rule.interval} ${unit}`;
  }

  // Days of week (for weekly)
  if (rule.frequency === 'weekly' && rule.daysOfWeek && rule.daysOfWeek.length > 0) {
    const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
    const selectedDays = rule.daysOfWeek.map((d) => dayNames[d]).join(', ');
    summary += ` on ${selectedDays}`;
  }

  // Day of month (for monthly)
  if (rule.frequency === 'monthly' && rule.dayOfMonth) {
    summary += ` on day ${rule.dayOfMonth}`;
  }

  // End condition
  if (rule.endType === 'after' && rule.endCount) {
    summary += `, ends after ${rule.endCount} occurrences`;
  } else if (rule.endType === 'until' && rule.endDate) {
    summary += `, ends on ${rule.endDate}`;
  }

  return summary;
}

